primary-cta.css:
.cta-primary {
  background: #DC2626;
  color: #FEF2F2;
  border: none;
  border-radius: 0;
  padding: 0.625rem 1.25rem;
  font-family: 'Jost', sans-serif;
  font-size: 0.6875rem;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  cursor: pointer;
  transition: background 250ms cubic-bezier(.16,1,.3,1);
}
.cta-primary:hover {
  background: #b91c1c;
}
.cta-primary:focus-visible {
  outline: 2px solid #D9895A;
  outline-offset: 3px;
}

ghost-button.css:
.cta-ghost {
  background: transparent;
  color: #C05E35;
  border: 1px solid #C05E35;
  border-radius: 0;
  padding: 0.625rem 1.25rem;
  font-family: 'Jost', sans-serif;
  font-size: 0.6875rem;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  cursor: pointer;
  transition: color 250ms cubic-bezier(.16,1,.3,1), border-color 250ms cubic-bezier(.16,1,.3,1);
}
.cta-ghost:hover {
  color: #D9895A;
  border-color: #D9895A;
}
.cta-ghost:focus-visible {
  outline: 2px solid #D9895A;
  outline-offset: 3px;
}

menu-tab.css:
.menu-tab {
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  color: #C4A882;
  padding: 0.5rem 0;
  font-family: 'Jost', sans-serif;
  font-size: 0.6875rem;
  font-weight: 500;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  cursor: pointer;
  transition: color 250ms cubic-bezier(.16,1,.3,1), border-color 250ms cubic-bezier(.16,1,.3,1);
}
.menu-tab[aria-selected="true"],
.menu-tab:hover {
  color: #D9895A;
  border-bottom-color: #D9895A;
}
.menu-tab:focus-visible {
  outline: 2px solid #D9895A;
  outline-offset: 3px;
}

gallery-card.css:
.gallery-grid {
  perspective: 1400px;
}
.gallery-card {
  margin: 0;
  overflow: hidden;
  aspect-ratio: 1 / 1;
  cursor: pointer;
  transition: transform 0.7s cubic-bezier(.16,1,.3,1), box-shadow 0.7s cubic-bezier(.16,1,.3,1);
  transform-style: preserve-3d;
}
.gallery-card:hover {
  transform: translateY(-8px) rotateX(1.6deg) rotateY(-1.6deg) scale(1.014);
  box-shadow: 0 20px 60px rgba(13,5,0,0.7), 0 8px 24px rgba(13,5,0,0.5);
}
.gallery-card img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.7s cubic-bezier(.16,1,.3,1);
  transform: translateZ(0);
}
.gallery-card:hover img {
  transform: scale(1.076) translateZ(14px);
}
@media (prefers-reduced-motion: reduce) {
  .gallery-card:hover { transform: none; }
  .gallery-card:hover img { transform: none; }
}

contact-card.css:
.contact-card {
  background: #2D1200;
  padding: 1.5rem;
  transition: transform 0.6s cubic-bezier(.16,1,.3,1), box-shadow 0.6s cubic-bezier(.16,1,.3,1);
  transform-style: preserve-3d;
}
.contact-card:hover {
  transform: translateY(-5px) rotateX(1deg) rotateY(-0.8deg) scale(1.006);
  box-shadow: 0 12px 40px rgba(13,5,0,0.6), 0 4px 16px rgba(13,5,0,0.4);
}
@media (prefers-reduced-motion: reduce) {
  .contact-card:hover { transform: none; }
}

mobile-fab.css:
.mobile-fab {
  position: fixed;
  bottom: 1.5rem;
  right: 1.5rem;
  width: 60px;
  height: 60px;
  border-radius: 50%;
  background: #DC2626;
  border: none;
  color: #FEF2F2;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 4px 24px rgba(220,38,38,0.45), 0 8px 32px rgba(220,38,38,0.25), inset 0 1px 0 rgba(255,255,255,0.1);
  transition: transform 0.35s cubic-bezier(.16,1,.3,1), box-shadow 0.35s cubic-bezier(.16,1,.3,1);
  z-index: 50;
}
.mobile-fab:hover {
  transform: translateY(-2px) scale(1.04);
}
.mobile-fab:focus-visible {
  outline: 2px solid #D9895A;
  outline-offset: 3px;
}
@media (min-width: 768px) { .mobile-fab { display: none; } }

back-to-top.css:
.back-to-top {
  border-radius: 999px;
  background: radial-gradient(circle, rgba(192,94,53,0.15), transparent 70%);
  border: 1px solid rgba(192,94,53,0.3);
  backdrop-filter: blur(8px);
  color: #D9895A;
  cursor: pointer;
  padding: 0.75rem;
  box-shadow: 0 0 0 1px rgba(192,94,53,0.15), 0 4px 20px rgba(13,5,0,0.5), inset 0 1px 0 rgba(192,94,53,0.2);
  transition: opacity 0.35s cubic-bezier(.16,1,.3,1), transform 0.35s cubic-bezier(.16,1,.3,1);
}
.back-to-top:focus-visible {
  outline: 2px solid #D9895A;
  outline-offset: 3px;
}

opening-hours-row.css:
.hours-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-radius: 0.55rem;
  padding: 0.5rem 1rem;
  background: rgba(45,18,0,0.6);
  color: #F5E6D0;
  font-family: 'Jost', sans-serif;
  font-size: 0.875rem;
}
.hours-day {
  color: #C4A882;
}
.hours-time {
  color: #F5E6D0;
  font-weight: 500;
}
